SELECT MAX(revision_date) AS latest_revision_date
FROM revisions
WHERE uom_code = 0;

SELECT COUNT(uom_code) AS active_uom_count
FROM uoms
WHERE is_active = 1;

SELECT unit_of_meas_name
FROM uoms
WHERE is_active = 1;

SELECT uom_type_name
FROM uom_types
WHERE is_active = 1;

SELECT conversion_id
FROM conversions
ORDER BY created_date;
